var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"칫, 다른 녀석들은 다 어디 간 거람?","JPN":"ちっ、他のやつらはどこなの？","ENG":"Bah, where did the others go?","TWN":"切，其他人都去哪兒了？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"숲에 들어온 뒤로 다들 흩어져서 여기가 어디인지 알 수가 없잖아?","JPN":"森に入ってからみんなばらけちゃって、ここがどこなのかわからないじゃない。","ENG":"We got separated after entering the forest. I can't even tell where I am.","TWN":"進入森林後大家全都散開了，完全不知道這裡是哪兒啊？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"응? 방금 뭔가가 부스럭거렸는데......?","JPN":"うん？　何か物音がした……？","ENG":"Mm? Something rustled just now.","TWN":"嗯？從剛剛就有什麼在沙沙作響……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"으아악!!","JPN":"うわあああっ！！","ENG":"Waah!","TWN":"呃啊啊！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"캬아악! 짜증나! 누가 여기에 구멍을 뚫어놓은 거야?!","JPN":"もう！　むかつく！　誰がこんなところに穴を掘っておいたの！？","ENG":"Gwarrgggh! What the heck? Who dug a hole here?","TWN":"額啊啊！真煩人！是誰在這裡挖了一個洞啊？！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"후후, 항상 아카데미 최강이라고 잘난 체 하더니 꼴 좋다.","JPN":"フフ、アカデミー最強が口癖のくせにざまあだわ。","ENG":"Heh heh. Look at you. How can you call yourself the Academy's best?","TWN":"呼呼，總是自詡為學院最強的人，活該。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"최강이면 뭐 해? 발 밑의 함정도 못 피하잖아?","JPN":"本当に最強って名乗っていいの？　足元の落とし穴も避けられないのに。","ENG":"You couldn't even avoid the trap that was right underneath you.","TWN":"最強有什麼用？連腳下的陷阱都避不開？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"......그러는 너도 함정에 빠져 있는 것 같은데?","JPN":"……そんなあんたも一緒に罠に落ちてるみたいだけど？","ENG":"Then, why are you in the trap with me?","TWN":"……那你不也掉進陷阱裡了嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이거 어차피 학생회에서 만든 거잖아?","JPN":"これって生徒会で作ったものじゃない？","ENG":"Didn't you and the others at the Student Council dig this?","TWN":"這個是學生會挖的吧？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"설마 자기가 만든 함정에 빠지다니, 한심해서 못 봐 주겠네.","JPN":"まさか自分が作った罠にはまるなんて、情けなくて笑えてくるわ。","ENG":"I can't believe you fell into your own trap.","TWN":"居然會有人掉進自己挖的陷阱裡，真是可笑。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그건......!!","JPN":"そ、それは……！！","ENG":"W-well!","TWN":"那，那是……！！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"난 함정을 만들자는 의견만 냈지, 위치를 정한 건 학생회장님이라고!","JPN":"あたしは罠を作ろうと意見を出しただけで、位置を決めたのは生徒会長なの！","ENG":"I only made the suggestion. It was the Student President who decided where to dig!","TWN":"我只是提出了挖陷阱的建議，陷阱位置是學生會長選的！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"애초에 내가 함정 위치를 알면 대회에 참가하는 게 반칙이잖아!","JPN":"あたしが最初から落とし穴の位置を知ってたら、\\n大会に参加するのが反則になるでしょ！？","ENG":"Besides, it would have been cheating if I knew where the traps were!","TWN":"如果我早就知道陷阱的位置，那不就犯規了嗎！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"아무튼 됐어. 감히 낙오자 주제에 날 이렇게 귀찮게 만들다니......","JPN":"もういいわ。落ちこぼれのくせにここまで私に手を焼かせて……","ENG":"Oh, cut it out. How dare a loser like you bother me like this?","TWN":"算了，區區一個失敗者，竟敢這麼煩人……"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"여기서 나가기만 해 봐! 가만 안 둬!","JPN":"ここから出たらタダじゃ済まないからね！","ENG":"Once I get out of here, I'm going to make you pay for this!","TWN":"等我們出去了，看我怎麼收拾你！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"어, 어라? 이건 또 뭐야?","JPN":"え、えっ？　何よこれ？","ENG":"Err? What the heck is this?","TWN":"哎，哎呦？這又是什麼？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"무슨 끈끈이 같은 게 묻어 있잖아?","JPN":"なんか粘々しているのがついてる？","ENG":"I've got goo all over me.","TWN":"粘上了什麼黏糊糊的東西？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"운이 나쁘네! 몇몇 함정에는 초강력 접착제를 넣자고 했거든!","JPN":"ラッキーだね！　いくつかの罠には超強力接着剤を入れようって提案したの！","ENG":"Too bad. I suggested we poured super glue into some of the pits.","TWN":"運氣太差了！當時有人說在幾個陷阱裡放一些超強力黏合劑！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"카운터도 벗어나기 힘든 공업용 특수 접착제로 말이야!","JPN":"カウンターの力でも取れにくい工業用特殊接着剤でね！","ENG":"Industrial-strength glue at that, so that even Counters can't easily escape!","TWN":"那可是連制裁者都很難擺脫的工業用特種黏合劑！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자! 어디 나갈 수 있으면 나가 보시지!","JPN":"さあ！　抜け出せられるもんならやってみなさい！","ENG":"Now, let's see if you can get out of here.","TWN":"好了！看看從哪兒能出去吧！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이 얼간아! 너도 붙어 있는 주제에 뭘 좋아하는 거야?!","JPN":"バカじゃないの？　あんたもくっついちゃってるくせに何喜んでるの！？","ENG":"You idiot! You're stuck here, too. Why are you so happy?","TWN":"你個傻瓜！你也被黏到了，高興個什麼啦？！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"대체 무슨 정신머리로 이딴 함정을 기획한 건데!","JPN":"どういう神経でこんなクソみたいな罠を企画したわけ？","ENG":"How crazy are you, to come up with stupid traps like this?","TWN":"到底是什麼腦子的人才會做出這種陷阱！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나, 나라고 이렇게 될 줄 알았나......","JPN":"あ、あたしだってこうなるなんて思わなかったもん……","ENG":"W-who knew this would happen to me?","TWN":"誰，誰知道事情會變成這樣啊……"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아이디어 단계에선 분명 재미있을 줄 알았지, 뭐......","JPN":"アイデアの段階では面白いかなって思ったんだよ……","ENG":"When I came up with the idea, I just thought it'd be fun...","TWN":"當時策劃的時候，我以為會很有趣呢……"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"큭...... 여기서 어영부영 하다간 소원 구슬을 빼앗길 텐데......","JPN":"くっ……ここでグダグダしてたら願い玉を先に取られちゃうじゃない……","ENG":"Gah! I don't have time to waste here. I want the Wishing Ball!","TWN":"呃……在這裡浪費的話，許願珠該被搶走了……"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"난 반드시 소원을 빌어서 3종 슬레이어가 되어야 한다고!","JPN":"私は絶対に第3種スレイヤーになるという願いを叶えたいの！","ENG":"I must wish on it and become a Category 3 Slayer!","TWN":"我一定要許願成為3級屠戮者的！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"버둥거리면 접착제가 더 달라붙을 텐데......","JPN":"そんなにジタバタしたら接着剤がもっと絡んじゃうよ……","ENG":"You'd better stop moving. You're only getting more glue on you.","TWN":"越是掙扎，黏合劑黏得越緊……"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"망하아아아알!!","JPN":"くそおおおぉぉぉぉ！！","ENG":"Draaaaaaaaat!","TWN":"該死的啊啊啊！！"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"잠깐, 이게 무슨 소리지?","JPN":"まって、なんの音！？","ENG":"Wait, did you hear that?","TWN":"等等，這是什麼聲音？"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"말 돌리려고 해 봤자 소용없어!","JPN":"話をそらしても無駄だから！","ENG":"Don't try to change the subject!","TWN":"你別轉移話題！"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"여기서 나가기만 하면 정말 가만두지 않을 테니까!","JPN":"ここから出たらまずあんたのことから……","ENG":"I'm really going to beat you up once I get out of here!","TWN":"從這裡出去之後我是絕對不會放過你的！"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"말을 돌리는 게 아니야! 진짜 이상한 소리가 들렸다고......","JPN":"そらすつもりはないよ！　本当に何か音が聞こえるの……！","ENG":"I'm not trying to change the subject! I really heard something strange.","TWN":"我沒轉移話題！我是真的聽到了奇怪的聲音……"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"......저, 저길 봐!","JPN":"あ、あれを見て！","ENG":"L-look!","TWN":"……看，看那邊！"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_42"},{"id":"L48_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"치, 침식체? 어째서 침식체가 여기에......?","JPN":"し、侵食体！？　なんで侵食体がここに……？","ENG":"C-C.O.s! W-what are they doing here?","TWN":"侵，侵蝕體？這裡怎麼會有侵蝕體……？"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그것도 한 두 마리가 아니야.","JPN":"しかも1体だけじゃない。","ENG":"Not just a couple of them.","TWN":"還不是一兩隻。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"숲 여기저기에서 이쪽으로 오고 있다고!","JPN":"森のあちこちからこっちに向かって来てる！","ENG":"They're coming at us from everywhere!","TWN":"侵蝕體正從森林各處朝這邊衝來呢！"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"다 네 탓이야! 이래선 도망칠 수도 없잖아?!","JPN":"どうすんのよ！　これじゃ逃げられないでしょ！？","ENG":"This is all your fault! We can't even run now!","TWN":"全都怪你！現在還怎麼逃？！"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"대체 왜 여기에 접착제 같은 걸 넣어둔 거야!","JPN":"なんでここに接着剤なんかを入れたの！","ENG":"I can't believe you put glue in here!","TWN":"到底為什麼要在這裡放黏合劑這種鬼東西啊！"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"너희들, 그 안에서 뭐 해?","JPN":"あなたたち、そこで何してるの？","ENG":"What are you guys doing down there?","TWN":"你們，在那裡面幹什麼呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"너, 너는......!","JPN":"あ、あんたは……！","ENG":"Y-you!","TWN":"你，你……！"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"임시 편입생! 다행이다!","JPN":"臨時編入生！　よかった！","ENG":"Temporary transfer student! Thank God!","TWN":"臨時插班生！真是太好了！"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"흥! 놀리러 온 거라면 마음대로 하시지!","JPN":"ふん！　からかいに来たなら好きにして！","ENG":"Hmpf! If you came to make fun of us, go ahead!","TWN":"哼！如果你是來嘲笑我的，那就儘管嘲笑吧！"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"감정 싸움은 나중으로 미뤄 두는 게 어때?","JPN":"虚勢を張るのはあとにしたら？","ENG":"Why don't we put aside our feelings for now?","TWN":"現在還有時間做口舌之爭？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"침식체 밥이 되기 싫으면 어서 올라오는 편이 좋을 걸?","JPN":"侵食体の餌になりたくなければ、はやく上がってきたほうがいいと思うよ。","ENG":"You'd better come up if you don't want to be eaten by the C.O.s.","TWN":"如果不想成為侵蝕體的腹中食物，還是趕快上來的好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"하, 하지만 이건 엄청 강한 접착제라......","JPN":"で、でもすごく強い接着剤でくっついちゃって………","ENG":"B-but we're covered in super glue...","TWN":"不，不過這是非常強的黏合劑……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"우왓! 저, 정말 몸이 떠오르잖아?","JPN":"わっ！　か、体が浮いてきた！？","ENG":"Whoa! W-we're floating in the air!","TWN":"嗚哇！我，真的飛起來了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_18"},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"으으, 온 몸이 끈적끈적해......","JPN":"ううー全身がベタベタする……","ENG":"Aww, I'm sticky all over...","TWN":"噢噢，渾身都黏糊糊的……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"질척거리는 것도 질색이야. 당장 샤워하고 싶어......","JPN":"粘々してて気持ち悪い。今すぐシャワー浴びたい……","ENG":"I feel soooo gross. I want to go take a shower right now...","TWN":"我最討厭黏糊糊的了，好想馬上洗個澡……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"임시 편입생! 너 정말 굉장한 애였구나?!","JPN":"臨時編入生！　あなたって本当にすごい人だったんだね！","ENG":"Temporary transfer student! You're so amazing!","TWN":"臨時插班生！你真的好厲害啊？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"혹시 아카데미에 정식 편입하지 않을래?","JPN":"アカデミーに正式に編入するのはどう？","ENG":"Why don't you join the Academy for real?","TWN":"你要不要正式插班到學院？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회에 인재는 언제나 환영이거든!","JPN":"生徒会は有能な人材をいつでも歓迎しているよ！","ENG":"The Student Council always welcomes more talent!","TWN":"學生會永遠歡迎人才！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"흥. 그것 좀 도와 줬다고 바로 엉겨 붙네. 누가 낙오자 아니랄까 봐.","JPN":"ふん。一度助けられたからってすぐ媚び売っちゃって。落ちこぼれらしい考え方だわ。","ENG":"Hmpf! She helped you a little, and now you're starstruck. You're such a loser.","TWN":"哼，你可不要因為幫了我們一點兒忙就馬上黏上來，生怕別人不知道你是失敗者。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"함정에서 꺼내 준 건 고맙지만 난 우승을 양보할 생각이 없어.","JPN":"落とし穴から出してくれたのはありがたいけど、私は優勝を譲るつもりはない。","ENG":"Thank you for saving me, but I'm not going to yield the winner's prize.","TWN":"謝謝你救我出來，不過我可不會讓出冠軍寶座。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그 정도는 너도 알고 있겠지?","JPN":"それくらいはあんたも知っているでしょ？","ENG":"You know that, don't you?","TWN":"你應該知道吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그러니 지금부터 10초만 줄게.","JPN":"だから今から10秒あげる。","ENG":"So I'll give you just ten seconds.","TWN":"所以，從現在開始，給你10秒鐘。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......뭐?","JPN":"……え？","ENG":"What?","TWN":"……什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"다른 경쟁자도 있으니 여기서 10초만 기다려 줄게. 너 먼저 출발해.","JPN":"他のライバルもいるから、ここで10秒だけ待ってあげる。あんたが先に出発して。","ENG":"You're not the only competitor I have, so I'll give you ten seconds to go before I do.","TWN":"還有其他競爭者，我就在這裡等你10秒鐘。你先出發。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"나름 배려해 주는 거야? 의외로 귀여운 구석도 있네?","JPN":"それなりに配慮してくれてるの？　意外と可愛いところもあるじゃない。","ENG":"You're being considerate, huh? I didn't know you could be so cute.","TWN":"你還真體貼？沒想到你還有這麼可愛的一面？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"뭣? 귀, 귀여...... 워?","JPN":"は？　か、可愛い……？","ENG":"What? Cu-cu-cu... Cute?","TWN":"什麼？可，可……愛？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"하지만 지금은 그런 한가한 소릴 할 때가 아니야.","JPN":"でも今はそんな吞気なことを言っている場合じゃない。","ENG":"But this is no time to talk about that.","TWN":"不過現在可不是說這種閒話的時候。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"침식체들이 점점 늘어나고 있어.","JPN":"侵食体がどんどん増えてきてる。","ENG":"More C.O.s are showing up by the minute.","TWN":"侵蝕體正在慢慢增加。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"침식 재난도 일어나지 않았는데 이런 일이 벌어진다는 건......","JPN":"侵食災害も起きていないのに、こんな状況になるってことは……","ENG":"This is impossible, unless a Corruption Disaster occurred nearby, or...","TWN":"又沒發生侵蝕災難，發生這樣的事……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"아마 아티팩트인 소원 구슬이 저 녀석들을 끌어들이고 있어서겠지.","JPN":"おそらくアーティファクトの願い玉があいつらを引き寄せているんだろうね。","ENG":"that Artifact, the Wishing Ball, is attracting them.","TWN":"應該是人造神器許願珠把那些傢伙吸引過來的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그럴 리가!","JPN":"そ、そんな！","ENG":"N-no way!","TWN":"怎，怎麼可能！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"회장님이 그런 위험한 물건을 운동회 상품으로 내놓게 허락했을 리가 없어!","JPN":"会長がそんな危険な物を運動会の景品として許可するはずがない！","ENG":"The Student President wouldn't have approved of something so dangerous being given as the Field Day prize.","TWN":"會長不可能同意把那種危險物品拿出來當運動會獎品！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"보관 과정에서 문제가 생겼을 수도 있어.","JPN":"保管過程で問題が生じた可能性もあるわ。","ENG":"There could have been a problem storing it.","TWN":"也可能是保管過程中出了問題。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"어쩌면 발견한 탐험가가 아티팩트의 숨겨진 작동 조건을 놓쳤을지도 모르고.","JPN":"もしかしたら発見した探検家が、アーティファクトの隠し作動条件を見落としたのかもしれないし。","ENG":"Or its finder might have missed the Artifact's hidden activation condition.","TWN":"說不定是發現神器的探險家漏掉了人造神器隱藏的啟動條件。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그래서 다들 준비는 끝났지? 지금부터 열심히 달려야 할 거야.","JPN":"それじゃあ、みんな準備はいいよね？　これから全力で走らないといけないからね。","ENG":"Anyway, is everyone ready? From now on, we'll have to run as hard as we can.","TWN":"所以都準備好了嗎？從現在開始，必須全力開跑了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그래, 어서 학생회가 있는 안전한 곳으로 피하자!","JPN":"そうね、早く生徒会のいる安全な場所に逃げよう！","ENG":"Okay, let's go to the Student Council. We'll be safe there.","TWN":"沒錯，趕緊去學生會所在的安全場所吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"아니, 돌아가는 길은 이미 침식체들이 장악했어.","JPN":"いえ、帰り道はすでに侵食体に掌握されてる。","ENG":"No. The way back is already occupied by C.O.s.","TWN":"不是，回去的路已經被侵蝕體佔領了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그리고 서둘러 이 문제를 해결하지 않으면 섬 전체가 엉망이 될 거야.","JPN":"それに、急いでこの問題を解決しないと島全体がめちゃくちゃになるよ。","ENG":"Besides, we have to solve this problem before it affects the entire island.","TWN":"而且，如果不抓緊時間解決這個問題，整個島都會淪陷。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"다들 열심히 준비했던 운동회가...... 난장판이 된단 말이지?","JPN":"みんなで一生懸命準備した運動会が……めちゃくちゃになる！？","ENG":"Are you saying it can ruin the Field Day all of us worked so hard on?","TWN":"大家精心準備的運動會……會全部搞砸嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"맞아. 그러니까 우린 예정대로 숲을 돌파해서 소원 구슬을 찾으러 가야 돼.","JPN":"そう。だから私たちは予定どおり森を突破して願い玉を探しに行かないと。","ENG":"Right. So, we must go through the forest and find the Wishing Ball.","TWN":"沒錯，所以我們必須按照原定計劃走出森林，找到許願珠。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"소원을 빌어서 아티펙트의 힘만 소진시키면, 침식체들도 더 이상 나타나지 않을 테니까.","JPN":"願い事をしてアーティファクトの力をなくしちゃえば、侵食体もこれ以上現れないから。","ENG":"If we make a wish and drain the Artifact's power, it'll no longer attract C.O.s.","TWN":"只要通過許願使人造神器的力量耗盡，侵蝕體們也就不會再繼續出現了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"우효! 간단하네!","JPN":"ウヒョー！　簡単ね！","ENG":"Ooo, that's simple!","TWN":"噢吼！很簡單嘛！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"결국 내가 소원구슬을 얻어서 3종 슬레이어가 되면 모조리 해결이란 뜻이잖아!","JPN":"つまり私が願い玉を手に入れて第3種スレイヤーになればすべて解決って意味じゃない？","ENG":"In the end, I have to make a wish and become a Category 3 Slayer to solve this problem, right?","TWN":"終歸是需要我拿到許願珠，許願變成3級屠戮者，事情自然就解決了嘛！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"무슨 헛소리야? 누가 너한테 소원구슬을 넘겨 주기나 한대?","JPN":"何を言ってるの？　誰があなたに願い玉を渡すって？","ENG":"Are you crazy? Who says I'll give you the Wishing Ball?","TWN":"你在胡說八道什麼？誰說要把許願珠讓給你了？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"아앙? 너야말로 뭔 소리를 하는 거야?","JPN":"ああん？　あんたこそ何を言ってるわけ？","ENG":"Huh? What are you talking about?","TWN":"啊啊？你才胡說八道呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"소원구슬의 힘도 소모시키고, 지금 나타난 침식체들도 내가 쓸어 버리면 일석이조 아냐?","JPN":"願い玉の力も消耗させて、今現れた侵食体も私が一掃しちゃえば一石二鳥じゃない？","ENG":"By becoming a Category 3 Slayer, I can exhaust the Wishing Ball's power and wipe out these C.O.s. Can't you see?","TWN":"既能使許願珠的力量耗盡，我又能打倒現在出現的侵蝕體，這不是一箭雙雕嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그건 그렇지만......","JPN":"そ、それはそうだけど……","ENG":"T-true, but...","TWN":"是，是那樣沒錯，可是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어쨌든 안 돼! 네가 지금보다 더 잘난 척 하는 꼴은 절대로 못 봐!","JPN":"とにかくダメ！　ナイエルが今よりも偉そうにするのは絶対に見たくない！","ENG":"No! I'm not going to let you become more arrogant than you already are!","TWN":"總之不行！我可不想看你比現在更得意的樣子！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"맞아! 소원구슬로 내 최면마술을 완성시키면 침식체들을 상대할 수 있을 거야!","JPN":"そうだ！　願い玉であたしの催眠術が完成すれば侵食体なんかあっという間に解決できるよ！","ENG":"And I can use the Wishing Ball to complete my hypnosis magic and wipe out the C.O.s myself!","TWN":"對了！我要用許願珠完成我的催眠魔術，那樣就能對付侵蝕體了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"좀 봐 줬다고 기어 오르지 마! 이 인생의 패배자야!","JPN":"最近ちょっと大目に見てやったからって調子に乗らないことね！　人生の負け組のくせに！","ENG":"Just because I cut you some slack, it doesn't mean we're equals. I'm not a loser like you!","TWN":"你不要得了便宜還賣乖！你這個人生的失敗者！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"소원 구슬은 완전히! 절대적으로! 이견의 여지 없이 내 거야!","JPN":"願い玉は完全に！　絶対に！　異見の余地なく私のものだから！","ENG":"The Wishing Ball is completely, absolutely, and undeniably mine!","TWN":"許願珠必須是我的！完全！絕對！沒有任何異議！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"너 따위가 눈독들이게 놔둘 줄 알아?!","JPN":"あんたごときが欲しがっても無駄なんだから！","ENG":"I'm not going to let you take it away from me!","TWN":"你以為我會放任你這種傢伙覬覦許願珠嗎？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......계속 거기서 티격태격할 생각이지?","JPN":"……ずっとそこで言い争うつもり？","ENG":"Are you just going to stand there, bickering?","TWN":"……你們要繼續在那裡吵吵鬧鬧的嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그럼 소원 구슬은 내가 가질게. 얘기 잘하고 천천히 와.","JPN":"じゃあ、願い玉は私がもらうわ。話が終わったら、ゆっくり来てね。","ENG":"I hope you don't mind my taking the Wishing Ball. Take your time to settle things between you.","TWN":"那許願珠我就拿走了，你們聊完之後再慢慢過來吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"아, 안 돼! 이 치사한 녀석! 거기 서!","JPN":"ダ、ダメ！　このずるい奴め！　止まれ！","ENG":"Oh, no! You cheater! Stop right there!","TWN":"啊，不行！你這個卑鄙的傢伙！站住！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나, 나도 같이 가!!","JPN":"お、置いていかないで！！","ENG":"C-come with me!","TWN":"我，我也一起去！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};